import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Menu, X, Scale } from 'lucide-react';

const navLinks = [
  { name: 'Home', href: '#home' },
  { name: 'Practice Areas', href: '#practice' },
  { name: 'About', href: '#about' },
  { name: 'Team', href: '#team' },
  { name: 'Contact', href: '#contact' },
];

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const styles = {
    nav: {
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      zIndex: 50,
      padding: '0 24px',
      transition: 'all 0.3s ease',
      backgroundColor: isScrolled ? 'rgba(255, 255, 255, 0.95)' : 'transparent',
      backdropFilter: isScrolled ? 'blur(20px)' : 'none',
      borderBottom: isScrolled ? '1px solid rgba(0,0,0,0.1)' : 'none',
    },
    container: {
      maxWidth: '1280px',
      margin: '0 auto',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      height: '80px',
    },
    logo: {
      display: 'flex',
      alignItems: 'center',
      gap: '12px',
      textDecoration: 'none',
      color: isScrolled ? '#123524' : '#fff',  // Changes on scroll
    },
    logoIcon: {
      width: '40px',
      height: '40px',
      backgroundColor: '#e2bc6f',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
    },
    logoText: {
      fontFamily: 'Playfair Display, serif',
      fontSize: '20px',
      fontWeight: 700,
      color: isScrolled ? '#123524' : '#fff',  // Changes on scroll
    },
    logoAccent: {
      color: '#e2bc6f',  // Accent stays the same
    },
    navLinks: {
      display: 'flex',
      alignItems: 'center',
      gap: '32px',
    },
    navLink: {
      color: isScrolled ? '#123524' : '#a1a1aa',  // Changes on scroll
      textDecoration: 'none',
      fontSize: '14px',
      transition: 'color 0.3s ease',
    },
    ctaButton: {
      padding: '12px 24px',
      backgroundColor: '#e2bc6f',
      color: '#000',
      fontWeight: 700,
      fontSize: '12px',
      textTransform: 'uppercase',
      letterSpacing: '2px',
      border: 'none',
      cursor: 'pointer',
      textDecoration: 'none',
    },
    mobileMenuBtn: {
      display: 'none',
      background: 'none',
      border: 'none',
      color: isScrolled ? '#123524' : '#fff',  // Changes on scroll
      cursor: 'pointer',
    },
    mobileMenu: {
      position: 'absolute',
      top: '80px',
      left: 0,
      right: 0,
      backgroundColor: isScrolled ? 'rgba(255, 255, 255, 0.95)' : 'rgba(15, 15, 16, 0.95)',
      backdropFilter: 'blur(20px)',
      padding: '24px',
      display: 'flex',
      flexDirection: 'column',
      gap: '16px',
    },
  };

  return (
    <nav style={styles.nav}>
      <div style={styles.container}>
        <a href="#home" style={styles.logo}>
          <div style={styles.logoIcon}>
            <Scale size={20} color="#000" />
          </div>
          <span style={styles.logoText}>
            Адвокат<span style={styles.logoAccent}> Цонева</span>
          </span>
        </a>

        <div style={styles.navLinks} className="desktop-nav">
          {navLinks.map((link) => (
            <a key={link.name} href={link.href} style={styles.navLink}>
              {link.name}
            </a>
          ))}
        </div>

        <a href="#contact" style={styles.ctaButton} className="desktop-nav">
          Консултация
        </a>

        <button
          style={styles.mobileMenuBtn}
          className="mobile-menu-btn"
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
          {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {isMobileMenuOpen && (
        <div style={styles.mobileMenu}>
          {navLinks.map((link) => (
            <a
              key={link.name}
              href={link.href}
              style={{ 
                ...styles.navLink, 
                fontSize: '18px',
                color: isScrolled ? '#123524' : '#fff' 
              }}
              onClick={() => setIsMobileMenuOpen(false)}
            >
              {link.name}
            </a>
          ))}
          <a href="#contact" style={{ ...styles.ctaButton, textAlign: 'center' }}>
            Консултация
          </a>
        </div>
      )}

      <style>{`
        @media (max-width: 768px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: block !important; }
        }
      `}</style>
    </nav>
  );
};

export default Navbar;
